def login_redirect(request, login_url="/login/", next_param="next"):
    from urllib.parse import urlencode, urlparse, urlunparse, parse_qs

    next_url = request.GET.get(next_param) or request.POST.get(next_param) or request.META.get("HTTP_REFERER") or "/"

    parsed_login = urlparse(login_url)
    query = parse_qs(parsed_login.query)
    query[next_param] = [next_url]
    new_query = urlencode(query, doseq=True)

    return urlunparse((
        parsed_login.scheme,
        parsed_login.netloc,
        parsed_login.path,
        parsed_login.params,
        new_query,
        parsed_login.fragment,
    ))